class Solution {
    public int numSub(String s) {
        long currentCount = 0;
        long total = 0;
        int MOD = (int) (1e9 + 7);
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') {
                currentCount++;
            } else {
                if (currentCount > 0) {
                    total += currentCount * (currentCount + 1) / 2;
                    currentCount = 0;
                }
            }
        }
        if (currentCount > 0) {
            total += currentCount * (currentCount + 1) / 2;
        }
        return (int) (total % MOD);
    }
}

